static float AW[70002],AB[1158];
static float*Wp[34],*Bp[34];
static void decW(){
static unsigned char r[72292];
const char*p=ED;int n=0;
while(*p){unsigned v=0;for(int i=0;i<5;i++){v=v*85+D[(unsigned char)*p];p++;}r[n++]=(v>>24)&0xFF;r[n++]=(v>>16)&0xFF;r[n++]=(v>>8)&0xFF;r[n++]=v&0xFF;}
for(int i=0;i<69992;i++)AW[i]=((int)r[i]-128);
for(int i=0;i<34;i++){Wp[i]=AW+WO[i];for(int j=0;j<WZ[i];j++)Wp[i][j]*=SC[i];}
auto h2f=[](unsigned short h){uint32_t e=(h>>10)&31,m=h&1023,s=(h&32768)<<16;if(!e)return 0.0f;uint32_t f=s|((e+112)<<23)|(m<<13);float v;memcpy(&v,&f,4);return v;};
for(int i=0;i<1148;i++){unsigned short h=r[69992+i*2]|(r[69992+i*2+1]<<8);AB[i]=h2f(h);}
for(int i=0;i<34;i++)Bp[i]=AB+BO[i];
}
static float ba[400000],bb[400000],s1[50000],s2[25000],s3[15000],obs[30000];
static void c33(const float*i,float*o,int H,int W,int ic,int oc,const float*w,const float*b){
int HW=H*W;for(int p=0;p<oc;p++){float B=b[p];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]=B;}
for(int c=0;c<ic;c++){const float*ip=i+c*HW;for(int p=0;p<oc;p++){float*op=o+p*HW;const float*wp=w+p*ic*9+c*9;
for(int y=0;y<H;y++)for(int x=0;x<W;x++){float s=0;for(int ky=-1;ky<=1;ky++){int iy=y+ky;if((unsigned)iy>=(unsigned)H)continue;for(int kx=-1;kx<=1;kx++){int ix=x+kx;if((unsigned)ix>=(unsigned)W)continue;s+=ip[iy*W+ix]*wp[(ky+1)*3+(kx+1)];}}op[y*W+x]+=s;}}}}
static void dw(const float*i,float*o,int H,int W,int ch,const float*w,const float*b){
int HW=H*W;for(int c=0;c<ch;c++){float B=b[c];for(int y=0;y<H;y++)for(int x=0;x<W;x++){float s=B;for(int ky=-1;ky<=1;ky++){int iy=y+ky;if((unsigned)iy>=(unsigned)H)continue;for(int kx=-1;kx<=1;kx++){int ix=x+kx;if((unsigned)ix>=(unsigned)W)continue;s+=i[c*HW+iy*W+ix]*w[c*9+(ky+1)*3+(kx+1)];}}o[c*HW+y*W+x]=s;}}}
static void pw(const float*i,float*o,int H,int W,int ic,int oc,const float*w,const float*b){
int HW=H*W;for(int p=0;p<oc;p++){float B=b[p];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]=B;}
for(int c=0;c<ic;c++){const float*ip=i+c*HW;for(int p=0;p<oc;p++){float wt=w[p*ic+c];float*op=o+p*HW;for(int j=0;j<HW;j++)op[j]+=ip[j]*wt;}}}
static void rl(float*d,int n){for(int i=0;i<n;i++)if(d[i]<0)d[i]=0;}
static void mp(const float*i,float*o,int H,int W,int C){
int oH=H/2,oW=W/2,iHW=H*W,oHW=oH*oW;for(int c=0;c<C;c++)for(int y=0;y<oH;y++)for(int x=0;x<oW;x++){int iy=y*2,ix=x*2;float v=i[c*iHW+iy*W+ix];v=max(v,i[c*iHW+iy*W+ix+1]);v=max(v,i[c*iHW+(iy+1)*W+ix]);v=max(v,i[c*iHW+(iy+1)*W+ix+1]);o[c*oHW+y*oW+x]=v;}}
static void ct(const float*i,float*o,int iH,int iW,int ic,int oc,const float*w,const float*b){
int oH=iH*2,oW=iW*2,oHW=oH*oW,iHW=iH*iW;for(int p=0;p<oc;p++)for(int j=0;j<oHW;j++)o[p*oHW+j]=b[p];for(int ci=0;ci<ic;ci++)for(int iy=0;iy<iH;iy++)for(int ix=0;ix<iW;ix++){float v=i[ci*iHW+iy*iW+ix];int oy=iy*2,ox=ix*2;for(int p=0;p<oc;p++)for(int ky=0;ky<2;ky++)for(int kx=0;kx<2;kx++)o[p*oHW+(oy+ky)*oW+(ox+kx)]+=v*w[ci*oc*4+p*4+ky*2+kx];}}
static void ap(const float*i,float*o,int H,int W,int C,int tH,int tW){
for(int c=0;c<C;c++)for(int oh=0;oh<tH;oh++){int h0=oh*H/tH,h1=(oh+1)*H/tH;for(int ow=0;ow<tW;ow++){int w0=ow*W/tW,w1=(ow+1)*W/tW;float s=0;int n=0;for(int y=h0;y<h1;y++)for(int x=w0;x<w1;x++){s+=i[c*H*W+y*W+x];n++;}o[c*tH*tW+oh*tW+ow]=s/n;}}}
static void cc(const float*a,const float*b,float*o,int H,int W,int ca,int cb){int HW=H*W;memcpy(o,a,ca*HW*4);memcpy(o+ca*HW,b,cb*HW*4);}
static void ln(const float*i,float*o,int ic,int oc,const float*w,const float*b){for(int p=0;p<oc;p++){float s=b[p];for(int j=0;j<ic;j++)s+=i[j]*w[p*ic+j];o[p]=s;}}
static void sp(const float*i,float*t,float*o,int H,int W,int ic,int oc,int di,int dbi,int pi,int pbi){dw(i,t,H,W,ic,Wp[di],Bp[dbi]);pw(t,o,H,W,ic,oc,Wp[pi],Bp[pbi]);rl(o,oc*H*W);}
static float ft[128],ph1[128],ph2[128],al[16];
static void fwd(){static float t1[400000],t2[400000];
c33(obs,t1,64,64,7,8,Wp[0],Bp[0]);rl(t1,8*4096);
c33(t1,s1,64,64,8,8,Wp[1],Bp[1]);rl(s1,8*4096);mp(s1,ba,64,64,8);
sp(ba,t1,t2,32,32,8,16,2,2,3,3);
sp(t2,t1,s2,32,32,16,16,4,4,5,5);mp(s2,ba,32,32,16);
sp(ba,t1,t2,16,16,16,32,6,6,7,7);
sp(t2,t1,s3,16,16,32,32,8,8,9,9);mp(s3,ba,16,16,32);
sp(ba,t1,t2,8,8,32,64,10,10,11,11);
sp(t2,t1,bb,8,8,64,64,12,12,13,13);
ct(bb,ba,8,8,64,32,Wp[14],Bp[14]);cc(ba,s3,bb,16,16,32,32);
sp(bb,t1,t2,16,16,64,32,15,15,16,16);
sp(t2,t1,ba,16,16,32,32,17,17,18,18);
ct(ba,bb,16,16,32,16,Wp[19],Bp[19]);cc(bb,s2,ba,32,32,16,16);
sp(ba,t1,t2,32,32,32,16,20,20,21,21);
sp(t2,t1,bb,32,32,16,16,22,22,23,23);
ct(bb,ba,32,32,16,8,Wp[24],Bp[24]);cc(ba,s1,bb,64,64,8,8);
sp(bb,t1,t2,64,64,16,8,25,25,26,26);
sp(t2,t1,ba,64,64,8,8,27,27,28,28);
pw(ba,bb,64,64,8,4,Wp[29],Bp[29]);
static float pl[64];ap(bb,pl,64,64,4,4,4);
ln(pl,ft,64,128,Wp[30],Bp[30]);rl(ft,128);
ln(ft,ph1,128,128,Wp[31],Bp[31]);rl(ph1,128);
ln(ph1,ph2,128,128,Wp[32],Bp[32]);rl(ph2,128);
ln(ph2,al,128,16,Wp[33],Bp[33]);}
static void exO(){memset(obs,0,7*64*64*4);
for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(wG[y*W+x])obs[y*64+x]=1.0f;
for(int i=0;i<nA;i++)if(aX[i]<64&&aY[i]<64)obs[4096+aY[i]*64+aX[i]]=1.0f;
for(int b=0;b<nB;b++){if(!mB[bt[b].id]||bt[b].ln<=0)continue;int hx=bt[b].hx(),hy=bt[b].hy();if(hx<64&&hy<64)obs[8192+hy*64+hx]=1.0f;for(int j=1;j<bt[b].ln;j++){int x=bt[b].bx[j],y=bt[b].by[j];if(x<64&&y<64){float s=1.0f-j*0.1f;if(s<0.1f)s=0.1f;obs[12288+y*64+x]=s;}}}
for(int b=0;b<nB;b++){if(mB[bt[b].id]||bt[b].ln<=0)continue;int hx=bt[b].hx(),hy=bt[b].hy();if(hx<64&&hy<64)obs[16384+hy*64+hx]=1.0f;for(int j=1;j<bt[b].ln;j++){int x=bt[b].bx[j],y=bt[b].by[j];if(x<64&&y<64){float s=1.0f-j*0.1f;if(s<0.1f)s=0.1f;obs[20480+y*64+x]=s;}}}
float hm=max(H-1,1)*1.0f;for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(!wG[y*W+x])obs[24576+y*64+x]=(float)y/hm;}
int main(){ios_base::sync_with_stdio(false);cin.tie(nullptr);decW();
cin>>myId;cin.ignore();cin>>W;cin.ignore();cin>>H;cin.ignore();
for(int y=0;y<H;y++){string r;getline(cin,r);for(int x=0;x<W;x++)wG[y*W+x]=(r[x]=='#');}
int bp;cin>>bp;cin.ignore();
for(int i=0;i<bp;i++){int id;cin>>id;cin.ignore();mB[id]=true;my_bird_ids[n_my_birds++]=id;}
for(int i=0;i<bp;i++){int id;cin>>id;cin.ignore();}
while(true){cin>>nA;cin.ignore();if(cin.eof())break;
for(int i=0;i<nA;i++){cin>>aX[i]>>aY[i];cin.ignore();}
cin>>nB;cin.ignore();for(int i=0;i<nB;i++){string bd;cin>>bt[i].id>>bd;cin.ignore();pB(bt[i],bd);bt[i].ow=mB[bt[i].id]?0:1;}
exO();fwd();
int mi[4],nm=0;for(int i=0;i<nB;i++)if(mB[bt[i].id]&&bt[i].ln>0)mi[nm++]=i;bool fr=true;
for(int bi=0;bi<nm;bi++){Bot&bot=bt[mi[bi]];int nn_idx=0;for(int j=0;j<n_my_birds;j++){if(my_bird_ids[j]==bot.id){nn_idx=j;break;}}float*lg=al+nn_idx*4;int bd=-1,fc=bot.fc();if(fc!=-1)bd=(fc+2)%4;
int hx=bot.hx(),hy=bot.hy();auto is_fatal=[&](int d){int nx=hx+DX[d],ny=hy+DY[d];if(nx<0||nx>=W||ny<0||ny>=H||wG[ny*W+nx])return true;for(int b=0;b<nB;b++)for(int j=0;j<bt[b].ln;j++)if(bt[b].bx[j]==nx&&bt[b].by[j]==ny)return true;return false;};
int best=-1;float bS=-1e9;for(int d=0;d<4;d++){if(d==bd||is_fatal(d))continue;if(best==-1||lg[d]>bS){bS=lg[d];best=d;}}if(best==-1){bS=-1e9;for(int d=0;d<4;d++){if(d==bd)continue;if(best==-1||lg[d]>bS){bS=lg[d];best=d;}}}if(best==-1)best=0;
if(!fr)cout<<';';cout<<bot.id<<' '<<DN[best];fr=false;}
if(nm==0)cout<<"WAIT";cout<<endl;}}
